-- Seed: reading data for the test account (test@test.com)
--
-- Recreates the test user's 37 books and 212 reading sessions, captured from
-- the live capy-books project. Idempotent: it deletes the user's existing rows
-- first, then reinserts. Safe to run repeatedly.
--
-- Notes:
--   * embedding is intentionally omitted (nullable; regenerated out of band by
--     the search-sessions edge function).
--   * fts is a generated column and is populated automatically.
--   * The test user must already exist in auth.users.
--
-- Usage:
--   Supabase SQL editor: paste and run, or
--   psql "$DATABASE_URL" -f supabase/seeds/test_account_reading_data.sql

do $seed$
declare
  v_user uuid;
begin
  select id into v_user from auth.users where email = 'test@test.com';
  if v_user is null then
    raise exception 'Seed aborted: auth user % not found', 'test@test.com';
  end if;

  delete from public.reading_sessions where user_id = v_user;
  delete from public.books where user_id = v_user;



  raise notice 'Seeded % books and % reading sessions for %',
    (select count(*) from public.books where user_id = v_user),
    (select count(*) from public.reading_sessions where user_id = v_user),
    v_user;
end $seed$;
