  insert into public.books
    (id, user_id, title, author, cover_url, status, progress, rating, notes, isbn, pages, publish_year, description, created_at, updated_at)
  values
  ('b0000001-0000-0000-0000-000000000006', v_user, 'The Fellowship of the Ring', 'J.R.R. Tolkien', NULL, 'finished', '100', NULL, NULL, NULL, '423', '1954', 'Frodo Baggins inherits a mysterious ring and sets out on a perilous journey to destroy it before the Dark Lord Sauron can reclaim it.', '2025-11-27 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000001', v_user, 'The Name of the Wind', 'Patrick Rothfuss', NULL, 'finished', '100', NULL, NULL, NULL, '662', '2007', 'The tale of Kvothe, a legendary figure, as he recounts his own story of coming-of-age, study at the University, and quest for revenge.', '2025-11-27 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000025', v_user, 'The Silmarillion', 'J.R.R. Tolkien', NULL, 'finished', '100', NULL, NULL, NULL, '365', '1977', 'The mythopoeic history of Tolkien''s world, covering the creation of Arda, the wars of the First Age, and the tales that underpin The Lord of the Rings.', '2025-11-27 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000007', v_user, 'The Two Towers', 'J.R.R. Tolkien', NULL, 'finished', '100', NULL, NULL, NULL, '352', '1954', 'The Fellowship broken, the quest continues on two fronts as Frodo and Sam head to Mordor while Aragorn, Legolas, and Gimli pursue the Uruk-hai.', '2025-12-02 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000008', v_user, 'The Return of the King', 'J.R.R. Tolkien', NULL, 'finished', '100', NULL, NULL, NULL, '416', '1955', 'The concluding volume of The Lord of the Rings sees the War of the Ring come to its climax and the final destruction of the One Ring.', '2025-12-07 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000002', v_user, 'The Wise Man''s Fear', 'Patrick Rothfuss', NULL, 'finished', '100', NULL, NULL, NULL, '994', '2011', 'The second day of Kvothe''s story continues as he masters the art of sympathy, travels to foreign lands, and seeks the Chandrian.', '2025-12-07 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000014', v_user, 'The Final Empire', 'Brandon Sanderson', NULL, 'finished', '100', NULL, NULL, NULL, '541', '2006', 'In a world where ash falls from the sky and mists dominate the night, a crew of thieves plan an impossible heist to overthrow an immortal emperor.', '2025-12-12 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000003', v_user, 'The Way of Kings', 'Brandon Sanderson', NULL, 'finished', '100', NULL, NULL, NULL, '1007', '2010', 'On the storm-swept world of Roshar, war and intrigue collide as a surgeon-turned-soldier, a scheming scholar, and a young thief discover their roles in an ancient struggle.', '2025-12-17 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000015', v_user, 'The Well of Ascension', 'Brandon Sanderson', NULL, 'finished', '100', NULL, NULL, NULL, '590', '2007', 'Having defeated the Lord Ruler, Vin and Elend face political intrigue and besieging armies as they try to build a new world from the ashes of the old.', '2025-12-22 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000004', v_user, 'Words of Radiance', 'Brandon Sanderson', NULL, 'finished', '100', NULL, NULL, NULL, '1087', '2014', 'The second volume of the Stormlight Archive continues the story of Kaladin, Shallan, and Dalinar as the Everstorm approaches.', '2025-12-27 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000016', v_user, 'The Hero of Ages', 'Brandon Sanderson', NULL, 'finished', '100', NULL, NULL, NULL, '572', '2008', 'The Mistborn trilogy concludes as Vin and Elend race against time to discover the Hero of Ages and save the world from a force of ultimate destruction.', '2026-01-01 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000009', v_user, 'The Blade Itself', 'Joe Abercrombie', NULL, 'finished', '100', NULL, NULL, NULL, '531', '2006', 'Introducing a world of grey morality, three unlikely companions — a barbarian, a crippled torturer, and a disgraced knight — are drawn into a quest they did not choose.', '2026-01-06 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000010', v_user, 'Before They Are Hanged', 'Joe Abercrombie', NULL, 'finished', '100', NULL, NULL, NULL, '543', '2007', 'The second First Law book follows three converging storylines across a brutal war while a mysterious quest leads beyond the edge of the world.', '2026-01-16 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000011', v_user, 'Last Argument of Kings', 'Joe Abercrombie', NULL, 'finished', '100', NULL, NULL, NULL, '639', '2008', 'The brutal conclusion to the First Law trilogy where every victory has a price and no one escapes unchanged — or unpunished.', '2026-01-26 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000012', v_user, 'A Game of Thrones', 'George R.R. Martin', NULL, 'finished', '100', NULL, NULL, NULL, '694', '1996', 'The first book in A Song of Ice and Fire follows noble houses of Westeros as they vie for control of the Iron Throne while an ancient threat stirs in the north.', '2026-02-05 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000017', v_user, 'Assassin''s Apprentice', 'Robin Hobb', NULL, 'finished', '100', NULL, NULL, NULL, '356', '1995', 'Young Fitz, royal bastard son, is trained as an assassin while navigating palace politics and discovering his mysterious magical gifts.', '2026-02-15 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000019', v_user, 'The Lies of Locke Lamora', 'Scott Lynch', NULL, 'finished', '100', NULL, NULL, NULL, '752', '2006', 'In the city of Camorr, a band of con artists calling themselves the Gentleman Bastards run increasingly elaborate schemes — until they cross the wrong people.', '2026-02-25 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000020', v_user, 'The Night Circus', 'Erin Morgenstern', NULL, 'finished', '100', NULL, NULL, NULL, '387', '2011', 'A mysterious black-and-white circus arrives without warning and two young magicians are pitted against each other in a contest with stakes neither fully understands.', '2026-03-07 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000021', v_user, 'Uprooted', 'Naomi Novik', NULL, 'finished', '100', NULL, NULL, NULL, '438', '2015', 'A young woman is chosen by the Dragon, a powerful wizard, to live in his tower, and discovers her own magic as a dark, ancient forest threatens her village.', '2026-03-17 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000024', v_user, 'The Eye of the World', 'Robert Jordan', NULL, 'finished', '100', NULL, NULL, NULL, '782', '1990', 'Five young people from a small village are swept up in an epic quest when a mysterious woman and her warrior companion reveal that one of them may be the Dragon Reborn.', '2026-03-27 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000005', v_user, 'Oathbringer', 'Brandon Sanderson', NULL, 'reading', '76', NULL, NULL, NULL, '1243', '2017', 'The third Stormlight Archive book follows the Knights Radiant as they struggle to unite a fractured world while the Everstorm brings ancient enemies back.', '2026-05-16 15:56:17.099051+00', '2026-06-22 15:41:04.671+00'),
  ('b0000001-0000-0000-0000-000000000013', v_user, 'A Clash of Kings', 'George R.R. Martin', NULL, 'reading', '40', NULL, NULL, NULL, '761', '1998', 'Five kings wage war across Westeros while Daenerys seeks allies in the east and the Night''s Watch ventures beyond the Wall.', '2026-05-26 15:56:17.099051+00', '2026-06-22 15:41:04.671+00'),
  ('fdb23d24-5928-4f85-8b30-c4926dc948e7', v_user, 'Zbrodnia i Kara', 'Fiodor Dostojewski', 'https://books.google.com/books/content?id=6AdPEAAAQBAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api', 'to-read', NULL, NULL, NULL, '9788728098561', '621', '2021', '23-letni Rodion Raskolnikow kończy studia prawnicze, ale ciężka sytuacja finansowa jego rodziny utrudnia mu rozpoczęcie praktyki w zawodzie. Młody mężczyzna jest zwolennikiem filozofii, zgodnie z którą jednostka wybitna ma prawo dokonywać zbrodni na zwykłych ludziach. Raskolnikow publikuje na ten temat manifest w prasie. Nie chcąc dopuścić, by jego siostra wyszła za mąż wyłącznie dla pieniędzy, decyduje się zabić dla zarobku starą lichwiarkę, którą traktuje jako społeczną "wszę". Sytuacja komplikuje się, gdy na miejscu niespodziewanie pojawia się jej siostra Lizawieta. Po dokonaniu podwójnego zabójstwa wciąż przekonany do swoich racji Raskolnikow przechodzi załamanie nerwowe. Przygniatające przeczucie nieuniknionej kary sprowadza na niego gorączkę i majaki. Fiodor Dostojewski to jeden z najsłynniejszych klasyków literatury rosyjskiej, przeplatający w swoich utworach realizm i wyobraźnię. Mistrz prozy psychologicznej, w której jasno wyrażał swoją niechęć do socjalizmu i rewolucji. Uważał, że ma to niszczący wpływ na człowieka, pozbawia go wartości chrześcijańskich, które dla Dostojewskiego były niezwykle ważne.', '2026-06-05 08:22:26.694+00', '2026-06-05 08:23:11.517+00'),
  ('e80ca565-85c0-44bc-bdf7-73c4e2666e7b', v_user, 'Władca Pierścieni', 'J. R. R. Tolkien', 'https://books.google.com/books/content?id=dRBJPwAACAAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api', 'reading', '95', NULL, NULL, '9788375062182', '1122', '2008', NULL, '2026-06-05 08:22:40.076+00', '2026-06-22 15:41:04.671+00'),
  ('932325e1-f5ea-46fc-bd4d-711dd8ea7e45', v_user, 'Project Hail Mary', 'Andy Weir', 'https://covers.openlibrary.org/b/id/11200092-L.jpg', 'to-read', NULL, NULL, NULL, '9780593135204', '496', '2021', 'A lone astronaut must save Earth from an extinction-level threat.', '2026-06-07 16:47:45.781644+00', '2026-06-07 16:47:45.781644+00'),
  ('5e8c06b6-50c1-4654-99ac-74168ce567c2', v_user, 'The Pragmatic Programmer', 'Andy Hunt', 'https://covers.openlibrary.org/b/id/10143650-L.jpg', 'to-read', NULL, NULL, NULL, '9780135956915', '352', '1999', 'A classic on software craftsmanship.', '2026-06-07 17:05:05.028999+00', '2026-06-07 17:05:05.028999+00'),
  ('1c398b9b-2e0e-4e34-95a6-b2431e4e35c3', v_user, 'A Game of Thrones', 'George R. R. Martin', 'https://covers.openlibrary.org/b/isbn/9780553103540-L.jpg', 'to-read', NULL, NULL, NULL, '9780553103540', '694', '1996', 'The first novel in George R. R. Martin''s A Song of Ice and Fire series. In the mythical continent of Westeros, several powerful families fight for control of the Iron Throne, while an ancient enemy awakens beyond the Wall in the far north.', '2026-06-07 17:22:15.789787+00', '2026-06-07 17:22:15.789787+00'),
  ('fd1aa669-86fb-4d83-9449-68061ffa0646', v_user, 'The Name of the Wind', 'Patrick Rothfuss', NULL, 'finished', '100', NULL, NULL, NULL, '662', '2007', NULL, '2026-06-08 16:36:07.065+00', '2026-06-08 16:37:15.989+00'),
  ('7ac805f0-3cd4-45a6-84b3-7c00737db7f5', v_user, 'Piranesi', 'Susanna Clarke', NULL, 'to-read', NULL, NULL, NULL, NULL, '272', '2020', NULL, '2026-06-08 16:36:07.065+00', '2026-06-08 16:36:07.065+00'),
  ('88ec84e1-ff2a-48f1-b877-833d464e703f', v_user, 'Klara and the Sun', 'Kazuo Ishiguro', NULL, 'finished', NULL, '4', NULL, NULL, '320', '2021', NULL, '2026-06-08 16:36:07.065+00', '2026-06-08 16:36:07.065+00'),
  ('e21893e8-ef95-433f-b362-86228a1d24a4', v_user, 'Dune', 'Frank Herbert', NULL, 'reading', '84', NULL, NULL, NULL, '688', '1965', NULL, '2026-06-08 16:36:07.065+00', '2026-06-22 15:41:04.671+00'),
  ('5876c2c0-dbe6-4ab0-857a-52b41fb6ad6f', v_user, 'The Left Hand of Darkness', 'Ursula K. Le Guin', NULL, 'finished', NULL, '5', NULL, NULL, '304', '1969', NULL, '2026-06-08 16:36:07.065+00', '2026-06-08 16:36:07.065+00'),
  ('b0000001-0000-0000-0000-000000000018', v_user, 'Royal Assassin', 'Robin Hobb', NULL, 'to-read', NULL, NULL, NULL, NULL, '675', '1996', 'Fitz returns to court only to find it riven with treachery as the Red-Ship Raiders continue to devastate the kingdom.', '2026-06-10 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000022', v_user, 'The Black Prism', 'Brent Weeks', NULL, 'to-read', NULL, NULL, NULL, NULL, '628', '2010', 'The Prism, the most powerful man in the world, discovers he has an illegitimate son just as a rebellion threatens to engulf his empire.', '2026-06-12 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b0000001-0000-0000-0000-000000000023', v_user, 'Magician: Apprentice', 'Raymond E. Feist', NULL, 'to-read', NULL, NULL, NULL, NULL, '485', '1982', 'A young kitchen boy named Pug discovers he has magical talent and is taken as an apprentice, only for his world to be torn apart by an invasion from another realm.', '2026-06-13 15:56:17.099051+00', '2026-06-15 15:56:17.099051+00'),
  ('b93e79dc-6a81-4da2-a0ee-ededd0e42a9e', v_user, 'The Shadow of the Gods', 'John Gwynne', 'https://books.google.com/books/content?id=GfXeDwAAQBAJ&printsec=frontcover&img=1&zoom=1&source=gbs_api', 'to-read', NULL, NULL, NULL, '9780356514192', '503', '2021', '''A masterfully crafted, brutally compelling Norse-inspired epic'' Anthony Ryan THE GREATEST SAGAS ARE WRITTEN IN BLOOD. A century has passed since the gods fought and drove themselves to extinction. Now only their bones remain, promising great power to those brave enough to seek them out. As whispers of war echo across the land of Vigrið, fate follows in the footsteps of three warriors: a huntress on a dangerous quest, a noblewoman pursuing battle fame, and a thrall seeking vengeance among the mercenaries known as the Bloodsworn. All three will shape the fate of the world as it once more falls under the shadow of the gods. Set in a brand-new, Norse-inspired world, and packed with myth, magic and bloody vengeance, The Shadow of the Gods begins an epic new fantasy saga from bestselling author John Gwynne. Further praise for The Shadow of the Gods ''Visceral, heart-breaking and unputdownable'' Jay Kristoff ''A satisfying and riveting read. The well-realised characters move against a backdrop of a world stunning in its immensity. It''s everything I''ve come to expect from a John Gwynne book'' Robin Hobb ''A masterclass in storytelling . . . epic, gritty fantasy with an uncompromising amount of heart'' FanFiAddict ''Quintessential Gwynne honed to perfection . . . The Shadow of the Gods is absolutely stunning, one hell of an epic series opener and a spectacular dose of Viking-flavoured fantasy'' The Tattooed Book Geek ''Reminds me of all that I love in the fantasy genre. The Shadow of the Gods is an action-packed cinematic read'' Fantasy Hive', '2026-06-16 15:08:25.109+00', '2026-06-16 15:08:25.109+00'),
  ('cfb09b7f-647c-4e86-a260-0c65949a85a0', v_user, 'Harry Potter i Kamień filozoficzny', 'J.K. Rowling', NULL, 'to-read', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '2026-06-16 15:31:51.892+00', '2026-06-16 15:34:32.93+00');
  insert into public.reading_sessions
    (id, user_id, date, minutes, mood, notes, quote, quote_page, created_at)
  values
  ('a0000000-0000-0000-0000-000000000001', v_user, '2025-11-28', '45', 'thoughtful', 'Back in Middle-earth after years. The Shire chapters read like a warm blanket — I forgot how Tolkien eases you in.', NULL, NULL, '2025-11-28 21:15:00+00'),
  ('a0000000-0000-0000-0000-000000000002', v_user, '2025-11-29', '60', 'thoughtful', 'The Black Rider at Bag End. Tolkien''s horror lies in what he withholds. I kept glancing at the window.', NULL, NULL, '2025-11-29 21:30:00+00'),
  ('a0000000-0000-0000-0000-000000000003', v_user, '2025-11-30', '45', 'happy', 'Strider revealed at the Prancing Pony. One of the great introductions in all of fantasy. Short Sunday session.', NULL, NULL, '2025-11-30 20:00:00+00'),
  ('a0000000-0000-0000-0000-000000000004', v_user, '2025-12-01', '50', 'moved', 'Weathertop. Even knowing what happens, the dread still lands. Read with tea and a blanket by the radiator.', NULL, NULL, '2025-12-01 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000005', v_user, '2025-12-06', '90', 'thoughtful', 'Long Saturday morning session. Started The Silmarillion alongside this — the deep history makes the world richer.', NULL, NULL, '2025-12-06 10:30:00+00'),
  ('a0000000-0000-0000-0000-000000000006', v_user, '2025-12-07', '120', 'moved', 'Moria. The drum in the deep. Had to put the book down after Gandalf fell. Just sat with it for a while.', NULL, NULL, '2025-12-07 14:00:00+00'),
  ('a0000000-0000-0000-0000-000000000007', v_user, '2025-12-08', '45', 'thoughtful', 'Still processing Gandalf. Lothlorien shifts register completely — almost fairytale. The grief is embedded in the landscape.', NULL, NULL, '2025-12-08 21:20:00+00'),
  ('a0000000-0000-0000-0000-000000000008', v_user, '2025-12-09', '60', 'thoughtful', 'Galadriel''s mirror. Even Boromir''s corruption feels inevitable, not villainous. Also dipping into Ainulindale.', NULL, NULL, '2025-12-09 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000009', v_user, '2025-12-10', '30', 'happy', 'Short session, tired after work. But 30 minutes in the Elvish woods still beats an entire evening elsewhere.', NULL, NULL, '2025-12-10 22:00:00+00'),
  ('a0000000-0000-0000-0000-000000000010', v_user, '2025-12-11', '50', 'moved', 'Amon Hen and the breaking of the Fellowship. Reading it slowly — I don''t want to leave this part.', NULL, NULL, '2025-12-11 21:30:00+00'),
  ('a0000000-0000-0000-0000-000000000011', v_user, '2025-12-13', '90', 'motivated', 'Saturday long session. Boromir''s death. The Fellowship scattered. The scope of what lies ahead feels enormous.', NULL, NULL, '2025-12-13 11:00:00+00'),
  ('a0000000-0000-0000-0000-000000000012', v_user, '2025-12-14', '120', 'moved', 'Finished The Fellowship. The ending still breaks me. Consoled myself by moving into the Valaquenta.', NULL, NULL, '2025-12-14 15:00:00+00'),
  ('a0000000-0000-0000-0000-000000000013', v_user, '2025-12-15', '45', 'moved', 'Beren and Luthien begins. Tolkien wrote this for his wife and you feel it on every page. Quietly extraordinary.', NULL, NULL, '2025-12-15 21:15:00+00'),
  ('a0000000-0000-0000-0000-000000000014', v_user, '2025-12-16', '50', 'thoughtful', 'Started The Two Towers. Silmarillion in the mornings, Two Towers in the evenings — the rhythm feels right.', NULL, NULL, '2025-12-16 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000015', v_user, '2025-12-17', '45', 'happy', 'Pippin and Merry with the Ents. I always forget how much of Two Towers belongs to them. Treebeard is wonderful.', NULL, NULL, '2025-12-17 21:30:00+00'),
  ('a0000000-0000-0000-0000-000000000016', v_user, '2025-12-18', '30', 'bored', 'The genealogies in the Silmarillion are genuinely slowing me down. Dense but I know they''re necessary.', NULL, NULL, '2025-12-18 22:15:00+00'),
  ('a0000000-0000-0000-0000-000000000017', v_user, '2025-12-20', '90', 'motivated', 'Helm''s Deep! Read the battle twice. Tolkien''s restraint — telling it through Legolas''s arrow count.', NULL, NULL, '2025-12-20 10:00:00+00'),
  ('a0000000-0000-0000-0000-000000000018', v_user, '2025-12-21', '120', 'thoughtful', 'Isengard in ruins, Ents victorious. Saruman unmasked. Tolkien rewards patience so generously.', NULL, NULL, '2025-12-21 14:00:00+00'),
  ('a0000000-0000-0000-0000-000000000019', v_user, '2025-12-22', '40', 'moved', 'The Children of Hurin in the Silmarillion is bleaker than I remembered. Turin''s doom is relentless.', NULL, NULL, '2025-12-22 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000020', v_user, '2025-12-23', '60', 'thoughtful', 'Frodo and Sam''s section begins. Faramir is easily one of Tolkien''s finest creations.', NULL, NULL, '2025-12-23 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000021', v_user, '2025-12-24', '45', 'moved', 'Christmas Eve reading session. The Forbidden Pool. Sam''s loyalty is so quietly devastating.', NULL, NULL, '2025-12-24 19:00:00+00'),
  ('a0000000-0000-0000-0000-000000000022', v_user, '2025-12-26', '60', 'thoughtful', 'Earendil''s voyage in the Silmarillion. The beauty here redeems all the dense genealogy chapters.', NULL, NULL, '2025-12-26 16:00:00+00'),
  ('a0000000-0000-0000-0000-000000000023', v_user, '2025-12-27', '90', 'moved', 'Finished The Silmarillion — the ending of ages, quiet and vast. The Stairs of Cirith Ungol in Two Towers.', NULL, NULL, '2025-12-27 11:00:00+00'),
  ('a0000000-0000-0000-0000-000000000024', v_user, '2025-12-28', '120', 'motivated', 'Shelob''s Lair then immediately started The Return of the King. Tolkien''s horror writing is so underrated.', NULL, NULL, '2025-12-28 14:00:00+00'),
  ('a0000000-0000-0000-0000-000000000025', v_user, '2025-12-29', '50', 'moved', 'Sam believing Frodo is dead. The despair in this chapter is total. Tolkien doesn''t soften it at all.', NULL, NULL, '2025-12-29 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000026', v_user, '2025-12-30', '45', 'happy', 'Finished The Two Towers! A perfect December gift to myself. Two Towers is criminally underrated as a volume.', NULL, NULL, '2025-12-30 21:30:00+00'),
  ('a0000000-0000-0000-0000-000000000027', v_user, '2026-01-01', '90', 'motivated', 'New Year''s Day with Gondor. The Rohirrim ride to the siege. Few things in literature feel as epic as this.', NULL, NULL, '2026-01-01 15:00:00+00'),
  ('a0000000-0000-0000-0000-000000000028', v_user, '2026-01-02', '60', 'thoughtful', 'The Siege of Gondor. Denethor''s madness is so tragic — power and despair corroding a great mind.', NULL, NULL, '2026-01-02 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000029', v_user, '2026-01-03', '45', 'moved', 'The Battle of Pelennor Fields. "I am no man." Still gives me chills on every single reread.', NULL, NULL, '2026-01-03 20:30:00+00'),
  ('a0000000-0000-0000-0000-000000000030', v_user, '2026-01-04', '50', 'thoughtful', 'The Houses of Healing. Aragorn and Eowyn. A quiet chapter after so much chaos — needed exactly this.', NULL, NULL, '2026-01-04 21:00:00+00'),
  ('a0000000-0000-0000-0000-000000000031', v_user, '2026-01-05', '45', 'thoughtful', 'Frodo and Sam in Mordor. The hopelessness is so carefully calibrated. The ring-bearer chapters feel airless.', NULL, NULL, '2026-01-05 21:30:00+00'),
